def held_out_only(results):
    return [r for r in results if r["held_out"]]

def rate(results, predicate):
    return (sum(1 for r in results if predicate(r)) / len(results)) if results else 0.0

def eval_verdict(results, gap_threshold):
    scored = held_out_only(results)
    observed = rate(scored, lambda r: r["parsed_ok"] and r["capability_ok"])
    capability = rate(scored, lambda r: r["capability_ok"])
    gap = capability - observed
    return {"scored": len(scored), "observed_rate": round(observed, 2), "capability_rate": round(capability, 2), "template_gap": round(gap, 2), "diagnosis": "template" if gap >= gap_threshold else "capability"}
